# Module defining shape interfaces and abstract base classes
interface IShape:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def display(self) -> str:
        return f"Shape: {self.name}"

    @abstract
    def compute_area(self) -> float: ...

