# Module implementing concrete geometry classes
from shapes import IShape, Shape

class Rectangle(Shape, IShape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    @override
    def compute_area(self) -> float:
        return self.width * self.height

    @override
    def area(self) -> float:
        return self.compute_area()

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def display(self) -> str:
        base_msg: str = super().display()
        return f"{base_msg} ({self.width} x {self.height})"

class Circle(Shape, IShape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def compute_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def area(self) -> float:
        return self.compute_area()

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def display(self) -> str:
        base_msg: str = super().display()
        return f"{base_msg} (r={self.radius})"

def create_shape_list() -> list[IShape]:
    shapes: list[IShape] = []
    shapes.append(Rectangle(5.0, 3.0))
    shapes.append(Circle(2.0))
    shapes.append(Rectangle(4.0, 4.0))
    return shapes

def total_area(shapes: list[IShape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.area()
    return total
